import React, { useState, useRef, useEffect } from 'react';
import * as XLSX from 'xlsx';
import dbService from '../services/dbService';

// ... (keep all your existing DEFAULT_OFFICE_DATA, DEFAULT_EVENTS, DEFAULT_USERS here)
// I'll show the key changes - paste your existing data first

const Dashboard = ({ onLogout, currentUser }) => {
  // ... (keep all your existing state declarations)

  // IMPORTANT: Load data from database on mount, not from localStorage
  const [loading, setLoading] = useState(true);
  const [officesData, setOfficesData] = useState({});
  const [events, setEvents] = useState([]);
  const [users, setUsers] = useState([]);
  const [pendingReports, setPendingReports] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [activeMenu, setActiveMenu] = useState('dashboard');

  // Load data from database on component mount
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        // Force load from database
        const [loadedOffices, loadedEvents, loadedUsers, loadedReports, loadedNotifs, savedMenu] = await Promise.all([
          dbService.getOfficesData(),
          dbService.getEvents(),
          dbService.getUsers(),
          dbService.getPendingReports(),
          dbService.getNotifications(),
          dbService.getActiveMenu()
        ]);

        // Update states with database data
        if (loadedOffices && Object.keys(loadedOffices).length > 0) {
          setOfficesData(loadedOffices);
        } else {
          // If database empty, initialize with default data
          setOfficesData(DEFAULT_OFFICE_DATA);
          await dbService.saveOfficesData(DEFAULT_OFFICE_DATA);
        }

        if (loadedEvents && loadedEvents.length > 0) {
          setEvents(loadedEvents);
        } else {
          setEvents(DEFAULT_EVENTS);
          await dbService.saveEvents(DEFAULT_EVENTS);
        }

        if (loadedUsers && loadedUsers.length > 0) {
          setUsers(loadedUsers);
        } else {
          setUsers(DEFAULT_USERS);
          await dbService.saveUsers(DEFAULT_USERS);
        }

        if (loadedReports && loadedReports.length > 0) {
          setPendingReports(loadedReports);
        }

        if (loadedNotifs && loadedNotifs.length > 0) {
          setNotifications(loadedNotifs);
        }

        if (savedMenu) setActiveMenu(savedMenu);

        console.log('✅ Data loaded from database successfully');
      } catch (error) {
        console.error('Error loading from database:', error);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, []);

  // Save to database whenever data changes
  useEffect(() => {
    const saveToDatabase = async () => {
      if (!loading) {
        try {
          await dbService.syncAllData({
            officesData,
            events,
            users,
            pendingReports,
            notifications,
            activeMenu
          });
          console.log('✅ Data synced to database');
        } catch (error) {
          console.error('Error syncing to database:', error);
        }
      }
    };

    // Debounce save to avoid too many requests
    const timeoutId = setTimeout(saveToDatabase, 1000);
    return () => clearTimeout(timeoutId);
  }, [officesData, events, users, pendingReports, notifications, activeMenu, loading]);

  // Force refresh when window gains focus (for mobile sync)
  useEffect(() => {
    const refreshData = async () => {
      if (!loading) {
        try {
          const [freshEvents, freshOffices] = await Promise.all([
            dbService.getEvents(),
            dbService.getOfficesData()
          ]);
          if (freshEvents && JSON.stringify(freshEvents) !== JSON.stringify(events)) {
            setEvents(freshEvents);
          }
          if (freshOffices && JSON.stringify(freshOffices) !== JSON.stringify(officesData)) {
            setOfficesData(freshOffices);
          }
        } catch (error) {
          console.error('Error refreshing data:', error);
        }
      }
    };

    window.addEventListener('focus', refreshData);
    // Refresh every 30 seconds
    const interval = setInterval(refreshData, 30000);

    return () => {
      window.removeEventListener('focus', refreshData);
      clearInterval(interval);
    };
  }, [loading, events, officesData]);

  // Role helpers (keep your existing role logic)
  const rawRole = currentUser?.role ?? '';
  const normalizedRole = rawRole.toString().trim().toUpperCase();
  const isSuperAdmin = normalizedRole.includes('SADMIN') || normalizedRole.includes('SUPER ADMIN') || normalizedRole.includes('SUPERADMIN');
  const isAdmin = !isSuperAdmin && (normalizedRole === 'ADMIN' || normalizedRole.includes('ADMIN'));
  const isUser = normalizedRole === 'USER';
  const canManageUsers = isSuperAdmin;
  const canEditEvents = isSuperAdmin || isAdmin;
  const canDeployEvents = isSuperAdmin;
  const canRejectEvents = isSuperAdmin;
  const canApproveReports = isSuperAdmin;

  // Rest of your existing component code...
  // Keep all your existing functions (handleAddEvent, handleDeleteEvent, etc.)

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>Syncing data across devices...</p>
      </div>
    );
  }

  // ... rest of your return statement
};

export default Dashboard;
